    }

    const special: ?[]const u8 = switch (key) {
        '\r' => "Enter",
        0x1b => "Escape",
        ' ' => "Space",
        '\t' => "Tab",
        0x7f => "BSpace",
        0x100 => "Up",
        0x101 => "Down",
        0x102 => "Left",
        0x103 => "Right",
        else => null,
    };

    if (special) |name| {
        @memcpy(buf[pos .. pos + name.len], name);
        pos += name.len;
        return buf[0..pos];
    }

    if (key < 0x80) {
        buf[pos] = @truncate(key);
        pos += 1;
        return buf[0..pos];
    }

    const rendered = std.fmt.bufPrint(buf[pos..], "U+{X}", .{key}) catch "?";
    return buf[0 .. pos + rendered.len];
}

